#include<bits/stdc++.h>
using namespace std;
int t,x[2001],y[2001],n;
bool v[2001][2001];
int dx[]={1,0,-1,0};
int dy[]={0,1,0,-1};
string bfs(){
    queue<int> q[3];
    q[0].push(1);
    q[1].push(1);
    q[2].push(0);
    while(!q[0].empty()){
        int x1=q[0].front();
        int y1=q[1].front();
        int sprt=q[2].front();
        if(x1==n&&y1==n) return "Yes\n";
        q[0].pop();
        q[1].pop();
        q[2].pop();
        v[x[sprt]][y[sprt]]=1;
        for(int i=0;i<4;i++){
            int mx=x1+dx[i];
            int my=y1+dy[i];
            if(mx<=0||my<=0||mx>n||my>n) continue;
            if(!v[mx][my]){
                q[0].push(mx);
                q[1].push(my);
                q[2].push(sprt+1);
                v[mx][my]=1;
            }
        }

    }
    return "No\n";
}
int main(){
    cin>>t;
    while(t--){
        cin>>n;
        for(int i=1;2*n-2>=i;i++){
            cin>>x[i]>>y[i];
        }
        memset(v,0,sizeof(v));
        cout<<bfs();
    }
    return 0;
}
